callbacks: {
  async signIn({ user, account }) {
    if (account.provider === "google") {
      return user.email?.endsWith("@company.com")
    }
    return true
  }
}

callbacks: {
  async redirect({ url, baseUrl }) {
    return url.startsWith(baseUrl) ? url : baseUrl
  }
}

